import React, { useState, useEffect } from 'react';
import './App.css';
import Topo from "./componentes/Topo";
import Rodape from "./componentes/Rodape";

function App() {
  const [produtos, setProdutos] = useState([]);
  const [carrinho, setCarrinho] = useState([]);
  const [etapa, setEtapa] = useState('vitrine'); 
  const [modoCadastro, setModoCadastro] = useState(false);
  const [usuario, setUsuario] = useState(null);
  const [formaPagamento, setFormaPagamento] = useState('');
  const [pedidoFinalizado, setPedidoFinalizado] = useState(null);
  const [formData, setFormData] = useState({
    nome: '',
    telefone: '',
    cep: '',
    endereco: '',
    cpf: '',
    email: '',
    senha: ''
  });

  // Busca produtos ao carregar a página
  useEffect(() => {
    fetch("http://localhost:3001/produtos")
      .then(res => res.json())
      .then(d => setProdutos(d))
      .catch(err => console.error("Erro ao carregar produtos:", err));
  }, []);

  const totalProd = carrinho.reduce((acc, i) => acc + (i.valor * i.qtd), 0);
  const valorFrete = formaPagamento === 'pix' ? 0 : 15.00;

  // Função de Autenticação (Login/Cadastro)
  const handleAuth = async () => {
    const rota = modoCadastro ? 'cadastrar' : 'login';
    
    try {
      const response = await fetch(`http://localhost:3001/${rota}`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(formData)
      });

      // Lemos como texto para evitar o erro de Unexpected Token <
      const texto = await response.text();
      let dados;
      
      try {
        dados = JSON.parse(texto);
      } catch (e) {
        throw new Error("O servidor retornou um erro HTML. Verifique o terminal do Node.");
      }

      if (!response.ok) {
        throw new Error(dados.message || "Erro na operação");
      }

      setUsuario(dados); 
      setEtapa('checkout'); 
      alert(modoCadastro ? "Cadastro realizado!" : "Bem-vindo(a)!");

    } catch (err) {
      alert("ERRO NO SISTEMA: " + err.message);
      console.error(err);
    }
  };
  // ---  FUNÇÃO DENTRO DO App() ANTES DO RETURN ---

const finalizar = async () => {
  if (!formaPagamento) return alert("Selecione uma forma de pagamento!");

  // Geramos um número de pedido aleatório para o ID
  const numeroPedido = Math.floor(Math.random() * 90000) + 10000;

  try {
    // Para cada item no carrinho, vamos salvar na tabela 'venda_cliente'
    for (const item of carrinho) {
      const dadosVenda = {
        id_pedido: numeroPedido,
        produto: item.produto,
        quantidade: item.qtd || 1,
        valor: item.valor,
        id_original_produto: item.id // ID para o UPDATE do estoque no Node
      };

      const response = await fetch("http://localhost:3000/vendas", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(dadosVenda)
      });

      if (!response.ok) {
        const erro = await response.json();
        throw new Error(erro.error || "Erro ao gravar venda");
      }
    }

    // Se chegou aqui, deu tudo certo!
    setPedidoFinalizado({
      numero: numeroPedido,
      total: totalProd + valorFrete,
      pagamento: formaPagamento
    });
    
    setCarrinho([]); // Limpa o carrinho
    setEtapa('sucesso'); // Muda para a tela de sucesso

  } catch (err) {
    console.error("Erro na finalização:", err);
    alert("❌ Falha ao processar pedido: " + err.message);
  }
};

  
  return (
    <div className="App">
      <Topo totalItens={carrinho.length} abrirCarrinho={() => setEtapa('carrinho')} temPedido={!!pedidoFinalizado} />
      
      <main className="conteudo-principal">
        {/* VITRINE */}
        {etapa === 'vitrine' && (
          <div className="grid-produtos">
            {produtos.map(p => (
              <div key={p.id} className="card">
                <img src={p.imagem_url} alt={p.produto} />
                <h3>{p.produto}</h3>
                <p>R$ {parseFloat(p.valor).toFixed(2)}</p>
                <button onClick={() => { setCarrinho([...carrinho, {...p, qtd:1}]); setEtapa('carrinho'); }}>Comprar</button>
              </div>
            ))}
          </div>
        )}

        {/* CARRINHO */}
        {etapa === 'carrinho' && (
          <div className="container-venda">
            <h2>🛒 Carrinho</h2>
            {carrinho.map((i, index) => (
              <div key={index} className="item-lista">
                <span>{i.produto}</span>
                <span>R$ {parseFloat(i.valor).toFixed(2)}</span>
              </div>
            ))}
            <h3>Total: R$ {totalProd.toFixed(2)}</h3>
            <button className="btn-p" onClick={() => setEtapa('login')}>Ir para Identificação</button>
            <button className="btn-v" onClick={() => setEtapa('vitrine')}>Voltar</button>
          </div>
        )}

        {/* LOGIN / CADASTRO */}
        {etapa === 'login' && (
          <div className="container-venda">
            <h2>{modoCadastro ? "📝 Cadastro" : "🔐 Login"}</h2>
            
            <input className="in-v" type="email" placeholder="E-mail" value={formData.email} onChange={e => setFormData({...formData, email: e.target.value})} />
            <input className="in-v" type="password" placeholder="Senha" value={formData.senha} onChange={e => setFormData({...formData, senha: e.target.value})} />
            
            {modoCadastro && (
              <>
                <input className="in-v" type="text" placeholder="Nome Completo" value={formData.nome} onChange={e => setFormData({...formData, nome: e.target.value})} />
                <input className="in-v" type="text" placeholder="Telefone" value={formData.telefone} onChange={e => setFormData({...formData, telefone: e.target.value})} />
                <input className="in-v" type="text" placeholder="CEP" value={formData.cep} onChange={e => setFormData({...formData, cep: e.target.value})} />
                <input className="in-v" type="text" placeholder="Endereço" value={formData.endereco} onChange={e => setFormData({...formData, endereco: e.target.value})} />
                <input className="in-v" type="text" placeholder="CPF (somente números)" value={formData.cpf} onChange={e => setFormData({...formData, cpf: e.target.value})} />
              </>
            )}
            
            <button className="btn-p" onClick={handleAuth}>{modoCadastro ? "Finalizar Cadastro" : "Entrar"}</button>
            <p onClick={() => setModoCadastro(!modoCadastro)} className="link-troca">
              {modoCadastro ? "Já tem conta? Faça Login" : "Não tem conta? Cadastre-se"}
            </p>
          </div>
        )}

        {/* CHECKOUT */}
        {etapa === 'checkout' && (
          <div className="container-venda">
            <h2>📍 Entrega para {usuario?.nome}</h2>
            <p>{usuario?.endereco} - {usuario?.cep}</p>
            <select className="in-v" value={formaPagamento} onChange={e => setFormaPagamento(e.target.value)}>
              <option value="">Escolha o Pagamento...</option>
              <option value="pix">Pix (Frete Grátis)</option>
              <option value="cartao">Cartão (+ R$ 15,00)</option>
            </select>
            <div className="resumo-f">
              <p>Produtos: R$ {totalProd.toFixed(2)}</p>
              <p>Frete: R$ {valorFrete.toFixed(2)}</p>
              <h3>Total Geral: R$ {(totalProd + valorFrete).toFixed(2)}</h3>
            </div>
            <button className="btn-p" disabled={!formaPagamento} onClick={finalizar}>Confirmar e Pagar</button>
          </div>
        )}

        {/* SUCESSO */}
        {etapa === 'sucesso' && (
          <div className="alerta-s">
            <h2>✅ Pedido #{pedidoFinalizado.numero} Confirmado!</h2>
            <p>Obrigado, {usuario?.nome}!</p>
            <p>Total: R$ {pedidoFinalizado.total.toFixed(2)} ({pedidoFinalizado.pagamento})</p>
            <button className="btn-p" onClick={() => { setEtapa('vitrine'); setPedidoFinalizado(null); }}>Voltar para Loja</button>
          </div>
        )}
      </main>
      <Rodape />
    </div>
  );
}

export default App;
